
#include "svg_helper.h"
int main(){
 string stem="04_comparison_sort_overview"; string title="04 Comparison Sort Overview"; vector<vector<int>> frames={{5,3,8,1,4,7},{3,5,8,1,4,7},{3,5,1,8,4,7},{3,1,5,4,8,7},{1,3,4,5,8,7},{1,3,4,5,7,8},{1,3,4,5,7,8}};
 vector<string> focus={"pairwise key comparison","red highlight shows current step","green part means completed state","autoplay checks whole process"};
 for(int k=0;k<frames.size();++k){ int W=1140,H=680; string s=startSVG(W,H,title,"Step "+to_string(k+1)+" / "+to_string(frames.size())+" - pairwise key comparison"); s+=box(50,120,610,390,"#fff","#bfd3e6"); set<int> hot; hot.insert(k%frames[k].size()); set<int> done; if(k>3) for(int i=0;i<k && i<frames[k].size();++i) done.insert(i); s+=T(90,160,"Array / key state",17,"#123","700"); s+=arr(frames[k],90,185,hot,done); for(int i=0;i+1<frames[k].size();++i) if((i+k)%2==0) s+=arrow(120+i*60,275,120+(i+1)*60,275); int bx=120, by=355; for(int i=0;i<frames[k].size();++i){int h=frames[k][i]*18; string col=hot.count(i)?"#ef4444":(done.count(i)?"#22c55e":"#93c5fd"); stringstream r; r<<"<rect x='"<<bx+i*62<<"' y='"<<by+140-h<<"' width='40' height='"<<h<<"' fill='"<<col<<"' stroke='#1f2937'/><text x='"<<bx+i*62+20<<"' y='"<<by+162<<"' text-anchor='middle' font-size='14' font-family='Arial'>"<<frames[k][i]<<"</text>"; s+=r.str();} s+=T(90,570,"Frame "+to_string(k+1)+": Comparison Sort Overview -- pairwise key comparison.",16,"#111827","700"); s+=sidebar(k+1,frames.size(),focus); s+=footer(W,H,stem+".cpp"); stringstream p; p<<"output/"<<stem<<"_steps/step_"<<setw(2)<<setfill('0')<<k+1<<".svg"; writeFile(p.str(),s+endSVG()); }
}
